+        pub fn remove(self: *Self, key: K) bool {
+            return self.data.remove(key);
+        }
+
+        pub fn contains(self: *Self, key: K) bool {
+            if (self.data.get(key)) |ref| {
+                return ref.isAlive();
+            }
+            return false;
+        }
+
+        pub fn len(self: *Self) usize {
+            var count: usize = 0;
+            var it = self.data.iterator();
+            while (it.next()) |entry| {
+                if (entry.value_ptr.isAlive()) {
+                    count += 1;
+                }
+            }
+            return count;
+        }
+    };
+}
